import{_ as t,c as r,o,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Monitoring et dépannage : Analyse des journaux de requêtes | Antigravity-Manager","description":"Apprendre le monitoring et dépannage Proxy Monitor d'Antigravity Tools. Via journaux de requêtes, filtrage et fonctionnalité de restauration de détails, localiser les erreurs 401/429/5xx et interruptions de streaming.","frontmatter":{"title":"Monitoring et dépannage : Analyse des journaux de requêtes | Antigravity-Manager","sidebarTitle":"Vérification journaux de requêtes","subtitle":"Monitoring et dépannage : Analyse des journaux de requêtes","description":"Apprendre le monitoring et dépannage Proxy Monitor d'Antigravity Tools. Via journaux de requêtes, filtrage et fonctionnalité de restauration de détails, localiser les erreurs 401/429/5xx et interruptions de streaming.","tags":["avancé","monitoring","dépannage","Proxy","journaux"],"prerequisite":["start-proxy-and-first-client","start-first-run-data","advanced-config"],"order":6},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"}`),i={name:"fr/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"};function s(n,e,l,d,u,c){return o(),r("div",null,[...e[0]||(e[0]=[a(`<h1 id="proxy-monitor-journaux-de-requetes-filtrage-restauration-de-details-et-exportation" tabindex="-1">Proxy Monitor : journaux de requêtes, filtrage, restauration de détails et exportation <a class="header-anchor" href="#proxy-monitor-journaux-de-requetes-filtrage-restauration-de-details-et-exportation" aria-label="Permalink to &quot;Proxy Monitor : journaux de requêtes, filtrage, restauration de détails et exportation&quot;">​</a></h1><p>Vous avez déjà démarré le reverse proxy local, mais dès qu&#39;apparaissent 401/429/500, interruption de streaming, ou &quot;soudain changement de compte/modèle&quot;, le dépannage devient facilement de la conjecture aveugle.</p><p>Ce cours ne traite qu&#39;une seule chose : utiliser <strong>Proxy Monitor</strong> pour restaurer chaque appel en &quot;preuve reproductible&quot;, vous permettant de savoir d&#39;où vient la requête, quel point de terminaison elle a touché, quel compte elle a utilisé, si le modèle a été mappé, et combien de tokens environ consommés.</p><h2 id="ce-que-vous-pourrez-faire-apres-ce-cours" tabindex="-1">Ce que vous pourrez faire après ce cours <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce cours&quot;">​</a></h2><ul><li>Ouvrir/suspendre l&#39;enregistrement sur la page <code>/monitor</code>, et comprendre si cela affecte Token Stats</li><li>Utiliser la zone de recherche, filtrage rapide, filtrage par compte, localiser rapidement un enregistrement de requête</li><li>Dans la popup de détails, voir et copier les messages Request/Response, analyser la cause de l&#39;échec</li><li>Connaître l&#39;emplacement de sauvegarde des données Proxy Monitor (<code>proxy_logs.db</code>) et le comportement de vidage</li><li>Comprendre la capacité réelle de &quot;exportation des journaux&quot; de la version actuelle (GUI vs commande backend)</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><ul><li>Vous ne voyez que &quot;échec d&#39;appel/délai&quot;, mais ne savez pas si l&#39;échec est sur l&#39;amont, le proxy, ou la configuration client</li><li>Vous soupçonnez avoir déclenché le mappage de modèle ou la rotation de compte, mais n&#39;avez pas de chaîne de preuves</li><li>Vous voulez restaurer le payload complet d&#39;une requête (surtout streaming/Thinking), mais ne le voyez pas dans les journaux</li></ul><h2 id="quand-utiliser-cette-methode" tabindex="-1">Quand utiliser cette méthode <a class="header-anchor" href="#quand-utiliser-cette-methode" aria-label="Permalink to &quot;Quand utiliser cette méthode&quot;">​</a></h2><ul><li>Vous dépannez : échec d&#39;auth 401, limitation 429, erreur amont 5xx, interruption streaming</li><li>Vous voulez confirmer : quel compte a été utilisé pour une certaine requête (<code>X-Account-Email</code>)</li><li>Vous faites une stratégie de routage de modèle, voulez vérifier &quot;nom de modèle client -&gt; nom de modèle réel mappé&quot;</li></ul><h2 id="🎒-preparation-avant-de-commencer" tabindex="-1">🎒 Préparation avant de commencer <a class="header-anchor" href="#🎒-preparation-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparation avant de commencer&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Conditions préalables</p><p>Proxy Monitor enregistre les &quot;requêtes reçues par le service reverse proxy&quot;. Donc vous devez au moins réussir à :</p><ul><li>Le service reverse proxy est démarré, et peut accéder <code>/healthz</code></li><li>Vous connaissez l&#39;URL de base et le port du reverse proxy actuel</li></ul><p>Si vous n&#39;avez pas réussi, d&#39;abord voir <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Démarrer le reverse proxy local et intégrer le premier client</a></strong>.</p></div><h2 id="qu-est-ce-que-proxy-monitor" tabindex="-1">Qu&#39;est-ce que Proxy Monitor ? <a class="header-anchor" href="#qu-est-ce-que-proxy-monitor" aria-label="Permalink to &quot;Qu&#39;est-ce que Proxy Monitor ?&quot;">​</a></h2><p><strong>Proxy Monitor</strong> est le &quot;tableau de bord des journaux de requêtes&quot; intégré à Antigravity Tools. Chaque requête entrant dans le reverse proxy local enregistre l&#39;heure, le chemin, le code d&#39;état, la durée, le modèle et le protocole, et essaie d&#39;extraire l&#39;utilisation des tokens de la réponse ; vous pouvez aussi cliquer sur un enregistrement unique pour voir les messages requête/réponse, l&#39;utiliser pour analyser la cause de l&#39;échec et le résultat de sélection de routage/compte.</p><div class="info custom-block"><p class="custom-block-title">Emplacement de sauvegarde des données</p><p>Les journaux Proxy Monitor sont écrits dans SQLite dans le répertoire de données : <code>proxy_logs.db</code>. Comment trouver le répertoire de données, comment sauvegarder, recommandé d&#39;abord revoir <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/start/first-run-data/">Premier démarrage à comprendre : répertoire de données, journaux, barre des tâches et démarrage automatique</a></strong>.</p></div><h2 id="idee-centrale-6-champs-a-surveiller" tabindex="-1">Idée centrale : 6 champs à surveiller <a class="header-anchor" href="#idee-centrale-6-champs-a-surveiller" aria-label="Permalink to &quot;Idée centrale : 6 champs à surveiller&quot;">​</a></h2><p>Dans un enregistrement Proxy Monitor (structure backend <code>ProxyRequestLog</code>), les plus utiles sont ces champs :</p><table tabindex="0"><thead><tr><th>Champ</th><th>Question à laquelle vous répondez</th></tr></thead><tbody><tr><td><code>status</code></td><td>Cette requête a-t-elle réussi ou échoué (200-399 vs autres)</td></tr><tr><td><code>url</code> / <code>method</code></td><td>Quel point de terminaison avez-vous touché (par exemple <code>/v1/messages</code>, <code>/v1/chat/completions</code>)</td></tr><tr><td><code>protocol</code></td><td>C&#39;est quel protocole OpenAI / Claude(Anthropic) / Gemini</td></tr><tr><td><code>account_email</code></td><td>Quel compte a été utilisé pour cette requête (depuis l&#39;en-tête de réponse <code>X-Account-Email</code>)</td></tr><tr><td><code>model</code> / <code>mapped_model</code></td><td>Le nom de modèle demandé par le client a-t-il été &quot;routé/mappé&quot; vers un autre modèle</td></tr><tr><td><code>input_tokens</code> / <code>output_tokens</code></td><td>Utilisation de tokens de cette requête (seulement si extractible)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">D&#39;abord &quot;résumé&quot;, puis détails si nécessaire</p><p>La page liste affiche seulement le résumé (sans corps request/response), cliquer sur un enregistrement chargera les détails complets depuis le backend, évitant de tirer trop de grands champs en une fois.</p></div><h2 id="suivez-moi-utiliser-un-appel-pour-completer-la-boucle-de-monitoring" tabindex="-1">Suivez-moi : utiliser un appel pour compléter &quot;la boucle de monitoring&quot; <a class="header-anchor" href="#suivez-moi-utiliser-un-appel-pour-completer-la-boucle-de-monitoring" aria-label="Permalink to &quot;Suivez-moi : utiliser un appel pour compléter &quot;la boucle de monitoring&quot;&quot;">​</a></h2><h3 id="etape-1-d-abord-creer-une-requete-qui-apparaitra-certainement" tabindex="-1">Étape 1 : D&#39;abord créer une &quot;requête qui apparaîtra certainement&quot; <a class="header-anchor" href="#etape-1-d-abord-creer-une-requete-qui-apparaitra-certainement" aria-label="Permalink to &quot;Étape 1 : D&#39;abord créer une &quot;requête qui apparaîtra certainement&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> Proxy Monitor enregistre seulement les requêtes reçues par le service reverse proxy. Utilisez d&#39;abord une requête la plus simple pour valider &quot;s&#39;il y a enregistrement&quot;, ensuite on parle de filtrage et détails.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-eSxTc" id="tab-h_YFl2g" checked><label data-title="macOS/Linux" for="tab-h_YFl2g">macOS/Linux</label><input type="radio" name="group-eSxTc" id="tab-zG9tsoy"><label data-title="Windows" for="tab-zG9tsoy">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) Vérification (point de terminaison qui existe certainement)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) Puis request une fois models (si vous avez activé l&#39;auth, n&#39;oubliez pas d&#39;ajouter header)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) Vérification (point de terminaison qui existe certainement)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) Puis request une fois models (si vous avez activé l&#39;auth, n&#39;oubliez pas d&#39;ajouter header)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div></div></div><p><strong>Ce que vous devriez voir</strong> : le terminal retourne <code>{&quot;status&quot;:&quot;ok&quot;}</code> (ou JSON similaire), et la réponse <code>/v1/models</code> (succès ou 401, ça va).</p><h3 id="etape-2-ouvrir-la-page-monitor-et-confirmer-l-etat-d-enregistrement" tabindex="-1">Étape 2 : Ouvrir la page Monitor et confirmer &quot;l&#39;état d&#39;enregistrement&quot; <a class="header-anchor" href="#etape-2-ouvrir-la-page-monitor-et-confirmer-l-etat-d-enregistrement" aria-label="Permalink to &quot;Étape 2 : Ouvrir la page Monitor et confirmer &quot;l&#39;état d&#39;enregistrement&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> Proxy Monitor a un interrupteur &quot;enregistrement/pause&quot;. Vous devez d&#39;abord confirmer l&#39;état actuel, sinon vous pourriez continuer à requêter, mais la liste est toujours vide.</p><p>Dans Antigravity Tools, ouvrez la barre latérale <strong>Panneau de monitoring API</strong> (route <code>/monitor</code>).</p><p>En haut de page, il y a un bouton avec un point :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ● Enregistrement en cours  [Recherche]  [Actualiser] [Effacer]      │</span></span>
<span class="line"><span>└───────────────────────────────────────────┘</span></span></code></pre></div><p>Si vous voyez &quot;En pause&quot;, cliquez une fois pour passer à &quot;Enregistrement en cours&quot;.</p><p><strong>Ce que vous devriez voir</strong> : l&#39;état du bouton devient &quot;Enregistrement en cours&quot; ; la liste commence à afficher les enregistrements de requête précédents.</p><h3 id="etape-3-utiliser-recherche-filtrage-rapide-pour-localiser-un-enregistrement" tabindex="-1">Étape 3 : Utiliser &quot;Recherche + filtrage rapide&quot; pour localiser un enregistrement <a class="header-anchor" href="#etape-3-utiliser-recherche-filtrage-rapide-pour-localiser-un-enregistrement" aria-label="Permalink to &quot;Étape 3 : Utiliser &quot;Recherche + filtrage rapide&quot; pour localiser un enregistrement&quot;">​</a></h3><p><strong>Pourquoi</strong> En dépannage réel, vous vous souvenez souvent seulement d&#39;un fragment : le chemin contient <code>messages</code>, ou le code d&#39;état est <code>401</code>, ou le nom de modèle contient <code>gemini</code>. La zone de recherche est conçue pour ce genre de souvenir.</p><p>La recherche Proxy Monitor traite votre entrée comme un &quot;mot-clé flou&quot;, dans le backend utilise SQL <code>LIKE</code> pour correspondre ces champs :</p><ul><li><code>url</code></li><li><code>method</code></li><li><code>model</code></li><li><code>status</code></li><li><code>account_email</code></li></ul><p>Vous pouvez essayer quelques mots-clés typiques :</p><ul><li><code>healthz</code></li><li><code>models</code></li><li><code>401</code> (si vous avez justement créé un 401)</li></ul><p>Vous pouvez aussi cliquer les boutons &quot;Filtrage rapide&quot; : <strong>Erreurs uniquement / Chat / Gemini / Claude / Image</strong>.</p><p><strong>Ce que vous devriez voir</strong> : la liste ne reste plus que la catégorie de requête que vous attendez.</p><h3 id="etape-4-cliquer-sur-details-restaurer-message-requete-message-reponse" tabindex="-1">Étape 4 : Cliquer sur détails, restaurer &quot;message requête + message réponse&quot; <a class="header-anchor" href="#etape-4-cliquer-sur-details-restaurer-message-requete-message-reponse" aria-label="Permalink to &quot;Étape 4 : Cliquer sur détails, restaurer &quot;message requête + message réponse&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> La liste suffit à répondre &quot;ce qui s&#39;est passé&quot;. Pour répondre &quot;pourquoi&quot;, vous devez généralement voir le payload complet requête/réponse.</p><p>Cliquez sur n&#39;importe quel enregistrement, une fenêtre de détails apparaît. Vous pouvez vérifier spécifiquement :</p><ul><li><code>Protocole</code> (OpenAI/Claude/Gemini)</li><li><code>Modèle utilisé</code> et <code>Modèle mappé</code></li><li><code>Compte utilisé</code></li><li><code>Consommation de tokens (entrée/sortie)</code></li></ul><p>Puis utilisez les boutons pour copier :</p><ul><li><code>Message de requête (Request)</code></li><li><code>Message de réponse (Response)</code></li></ul><p><strong>Ce que vous devriez voir</strong> : dans les détails, il y a deux blocs de prévisualisation JSON (ou texte) ; après copie, vous pouvez coller dans un ticket/note pour analyse.</p><h3 id="etape-5-besoin-de-reproduire-a-partir-de-zero-vider-les-journaux" tabindex="-1">Étape 5 : Besoin de &quot;reproduire à partir de zéro&quot;, vider les journaux <a class="header-anchor" href="#etape-5-besoin-de-reproduire-a-partir-de-zero-vider-les-journaux" aria-label="Permalink to &quot;Étape 5 : Besoin de &quot;reproduire à partir de zéro&quot;, vider les journaux&quot;">​</a></h3><p><strong>Pourquoi</strong> En dépannage, ce qu&#39;on craint le plus est &quot;les anciennes données interfèrent le jugement&quot;. Vider puis reproduire une fois, succès/échec sera très clair.</p><p>Cliquez le bouton &quot;Effacer&quot; en haut, une boîte de confirmation apparaît.</p><div class="danger custom-block"><p class="custom-block-title">C&#39;est une opération irréversible</p><p>Effacer supprime tous les enregistrements dans <code>proxy_logs.db</code>.</p></div><p><strong>Ce que vous devriez voir</strong> : après confirmation, la liste est vidée, les statistiques reviennent à 0.</p><h2 id="point-de-verification-✅" tabindex="-1">Point de vérification ✅ <a class="header-anchor" href="#point-de-verification-✅" aria-label="Permalink to &quot;Point de vérification ✅&quot;">​</a></h2><ul><li>[ ] Vous pouvez voir sur <code>/monitor</code> l&#39;enregistrement <code>/healthz</code> ou <code>/v1/models</code> que vous venez d&#39;émettre</li><li>[ ] Vous pouvez utiliser la zone de recherche pour filtrer un enregistrement (par exemple entrer <code>healthz</code>)</li><li>[ ] Vous pouvez cliquer sur un enregistrement pour voir les messages requête/réponse, et les copier</li><li>[ ] Vous savez que vider les journaux supprimera directement tous les enregistrements historiques</li></ul><h2 id="attention-aux-pieges-courants" tabindex="-1">Attention aux pièges courants <a class="header-anchor" href="#attention-aux-pieges-courants" aria-label="Permalink to &quot;Attention aux pièges courants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scénario</th><th>Ce que vous pourriez comprendre (❌)</th><th>Comportement réel (✓)</th></tr></thead><tbody><tr><td>&quot;En pause&quot; = aucune surcharge de monitoring</td><td>Penser que après pause, les requêtes ne seront pas analysées</td><td>La pause affecte seulement &quot;si écrire dans les journaux Proxy Monitor&quot;. Mais l&#39;analyse requête/réponse (y compris l&#39;analyse SSE des données streaming) se produira quand même, juste que les données analysées ne seront pas sauvegardées. Token Stats enregistrera quand même (que le monitoring soit activé ou non).</td></tr><tr><td>Journaux vides pour binaire/gros payload</td><td>Penser que le monitoring est cassé</td><td>Les requêtes/réponses binaires afficheront <code>[Binary Request Data]</code> / <code>[Binary Response Data]</code>. Le corps de réponse dépassant 100MB sera marqué <code>[Response too large (&gt;100MB)]</code> ; le corps de requête dépassant la limite ne sera pas enregistré.</td></tr><tr><td>Utiliser Monitor pour trouver &quot;qui a lancé la requête&quot;</td><td>Penser pouvoir remonter au processus client</td><td>Monitor enregistre les informations HTTP (méthode/chemin/modèle/compte), ne contient pas &quot;nom du processus appelant&quot;. Vous devez combiner les logs du client lui-même ou le sniffing réseau du système pour localiser la source.</td></tr><tr><td>Données Token Stats anormales quand monitoring activé</td><td>Penser erreur de statistique</td><td>Quand monitoring activé, Token Stats peut être enregistré deux fois (une fois au début de la fonction monitoring, une fois lors de l&#39;écriture asynchrone dans la base). C&#39;est le comportement du code source de la version actuelle.</td></tr></tbody></table><h2 id="exportation-et-conservation-a-long-terme-d-abord-clarifier-les-limites-de-capacite" tabindex="-1">Exportation et conservation à long terme : d&#39;abord clarifier les limites de capacité <a class="header-anchor" href="#exportation-et-conservation-a-long-terme-d-abord-clarifier-les-limites-de-capacite" aria-label="Permalink to &quot;Exportation et conservation à long terme : d&#39;abord clarifier les limites de capacité&quot;">​</a></h2><h3 id="_1-ce-que-gui-peut-faire-actuellement" tabindex="-1">1) Ce que GUI peut faire actuellement <a class="header-anchor" href="#_1-ce-que-gui-peut-faire-actuellement" aria-label="Permalink to &quot;1) Ce que GUI peut faire actuellement&quot;">​</a></h3><p>Dans l&#39;interface Monitor UI (<code>ProxyMonitor.tsx</code>) de la version actuelle, vous pouvez :</p><ul><li>Rechercher/filtrer/naviguer par pages</li><li>Cliquer sur détails pour voir et copier payload</li><li>Vider tous les journaux</li></ul><p>Mais <strong>pas de bouton &quot;exporter&quot; trouvé</strong> (l&#39;interface UI n&#39;a pas vu de bouton correspondant dans le code source).</p><h3 id="_2-quelles-capacites-d-exportation-le-backend-a-deja-convient-pour-developpement-secondaire" tabindex="-1">2) Quelles capacités d&#39;exportation le backend a déjà (convient pour développement secondaire) <a class="header-anchor" href="#_2-quelles-capacites-d-exportation-le-backend-a-deja-convient-pour-developpement-secondaire" aria-label="Permalink to &quot;2) Quelles capacités d&#39;exportation le backend a déjà (convient pour développement secondaire)&quot;">​</a></h3><p>Les commandes Tauri backend fournissent deux méthodes d&#39;exportation :</p><ul><li><code>export_proxy_logs(file_path)</code> : exporter &quot;tous les journaux&quot; de la base de données en fichier JSON</li><li><code>export_proxy_logs_json(file_path, json_data)</code> : écrire joliment votre tableau JSON entré dans un fichier (l&#39;entrée doit être au format tableau)</li></ul><p>Si vous voulez développer secondairement GUI, ou écrire votre propre script d&#39;appel, vous pouvez directement réutiliser ces commandes.</p><h3 id="_3-exportation-la-plus-simple-sauvegarder-directement-proxy-logs-db" tabindex="-1">3) Exportation la plus &quot;simple&quot; : sauvegarder directement <code>proxy_logs.db</code> <a class="header-anchor" href="#_3-exportation-la-plus-simple-sauvegarder-directement-proxy-logs-db" aria-label="Permalink to &quot;3) Exportation la plus &quot;simple&quot; : sauvegarder directement \`proxy_logs.db\`&quot;">​</a></h3><p>Parce que Proxy Monitor est essentiellement SQLite, vous pouvez aussi traiter <code>proxy_logs.db</code> comme &quot;paquet de preuves de dépannage&quot; à sauvegarder ensemble (par exemple avec <code>token_stats.db</code>). L&#39;emplacement du répertoire de données voir <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/start/first-run-data/">Premier démarrage à comprendre</a></strong>.</p><h2 id="a-lire" tabindex="-1">À lire <a class="header-anchor" href="#a-lire" aria-label="Permalink to &quot;À lire&quot;">​</a></h2><ul><li>Vouloir clarifier le mappage de modèles : <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/advanced/model-router/">Routage de modèles : mappage personnalisé, priorité des caractères génériques et stratégies prédéfinies</a></strong></li><li>Vouloir dépanner les problèmes d&#39;auth : <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/faq/auth-401/">401/Échec d&#39;auth : auth_mode, compatibilité Header et liste de configuration client</a></strong></li><li>Vouloir combiner Monitor avec statistiques de coûts : la section suivante parlera de Token Stats (<code>token_stats.db</code>)</li></ul><h2 id="resume-du-cours" tabindex="-1">Résumé du cours <a class="header-anchor" href="#resume-du-cours" aria-label="Permalink to &quot;Résumé du cours&quot;">​</a></h2><ul><li>La valeur de Proxy Monitor est &quot;reproductible&quot; : enregistre code d&#39;état/chemin/protocole/compte/mappage de modèle/utilisation de tokens, et fournit les détails de requête</li><li>Recherche et filtrage rapide sont l&#39;entrée de dépannage : d&#39;abord réduire la portée, puis cliquer sur détails pour voir payload</li><li>Vider les journaux est une opération irréversible ; l&#39;exportation tend actuellement plus vers &quot;capacité de développement secondaire&quot; et &quot;fichier de base de données sauvegardé&quot;</li></ul><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Le prochain cours, nous apprenons <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/advanced/token-stats/">Token Stats : métriques de statistiques de perspective de coût et interprétation des graphiques</a></strong>, transformant &quot;ça me semble cher&quot; en optimisation quantifiable.</p></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer les emplacements du code source</strong></summary><blockquote><p>Date de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Ligne</th></tr></thead><tbody><tr><td>Entrée page Monitor (monte ProxyMonitor)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Monitor.tsx#L1-L12" target="_blank" rel="noreferrer"><code>src/pages/Monitor.tsx</code></a></td><td>1-12</td></tr><tr><td>Interface Monitor : tableau/filtrage/popup détails</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L13-L713" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>13-713</td></tr><tr><td>Interface : lire configuration et synchroniser enable_logging</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L174-L243" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>174-243</td></tr><tr><td>Interface : basculer enregistrement (écrire config + set_proxy_monitor_enabled)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L254-L267" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>254-267</td></tr><tr><td>Interface : écoute événements temps réel (proxy://request) et déduplication</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L273-L355" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>273-355</td></tr><tr><td>Interface : vider journaux (clear_proxy_logs)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L389-L403" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>389-403</td></tr><tr><td>Interface : charger détails unique (get_proxy_log_detail)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L505-L519" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>505-519</td></tr><tr><td>Middleware monitoring : capturer requête/réponse, analyser token, écrire dans monitor</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L13-L337" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>13-337</td></tr><tr><td>ProxyMonitor : interrupteur enabled, écrire DB, envoyer événement</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L33-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>33-194</td></tr><tr><td>Serveur montage middleware monitoring (layer)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L183-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>183-194</td></tr><tr><td>Commandes Tauri : get/count/filter/detail/clear/export</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/proxy.rs#L180-L314" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/proxy.rs</code></a></td><td>180-314</td></tr><tr><td>SQLite : chemin proxy_logs.db, structure table et SQL filtrage</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L1-L416" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>1-416</td></tr><tr><td>Description design monitoring (peut différer de l&#39;implémentation, le code source prime)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-monitor-technical.md#L1-L53" target="_blank" rel="noreferrer"><code>docs/proxy-monitor-technical.md</code></a></td><td>1-53</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>MAX_REQUEST_LOG_SIZE = 100 * 1024 * 1024</code> : corps de requête maximal lisible par middleware monitoring (dépassera échouera)</li><li><code>MAX_RESPONSE_LOG_SIZE = 100 * 1024 * 1024</code> : corps de réponse maximal lisible par middleware monitoring (pour images etc. grosses réponses)</li></ul><p><strong>Fonctions/Commandes clés</strong> :</p><ul><li><code>monitor_middleware(...)</code> : au niveau HTTP collecter requête et réponse, et appeler <code>monitor.log_request(...)</code></li><li><code>ProxyMonitor::log_request(...)</code> : écrire en mémoire + SQLite, et pousser résumé via événement <code>proxy://request</code></li><li><code>get_proxy_logs_count_filtered(filter, errors_only)</code> / <code>get_proxy_logs_filtered(...)</code> : filtrage et pagination page liste</li><li><code>get_proxy_log_detail(log_id)</code> : charger corps request/response complet d&#39;un seul journal</li><li><code>export_proxy_logs(file_path)</code> : exporter tous les journaux en fichier JSON (l&#39;interface actuelle n&#39;expose pas le bouton)</li></ul></details>`,74)])])}const g=t(i,[["render",s]]);export{m as __pageData,g as default};
